function nextGeneration(grid: Array<[number, number]>): Array<[number, number]> {
  const survivors: Array<[number, number]> = [];
  const liveCells = new Set(grid.map(([x, y]) => `${x},${y}`));

  for (const [x, y] of grid) {
    let neighbors = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (liveCells.has(`${x + dx},${y + dy}`)) {
          neighbors++;
        }
      }
    }

    if (neighbors === 2) {
      survivors.push([x, y]);
    }
  }

  return survivors;
}
```

